import{_ as a,a as t,b as s,c as n,d as o,e as i}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as d,o as r,c as l,a2 as p}from"./chunks/framework.DnrXFDHb.js";const v=JSON.parse('{"title":"IP Geolocation and User Management","description":"","frontmatter":{},"headers":[],"relativePath":"en/Other/ip-geolocation-and-user-management.md","filePath":"en/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"en/Other/ip-geolocation-and-user-management.md"};function h(u,e,g,m,b,f){return r(),l("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-geolocation-and-user-management" tabindex="-1">IP Geolocation and User Management <a class="header-anchor" href="#ip-geolocation-and-user-management" aria-label="Permalink to &quot;IP Geolocation and User Management&quot;">​</a></h1><p>IP geolocation turns IP addresses in uploader records, login devices, and similar logs into approximate locations.</p><p>After it is configured, the admin panel can show upload and access origins more clearly. User Management also lets you block or restore upload access for suspicious IP addresses.</p><h2 id="where-to-configure-it" tabindex="-1">Where To Configure It <a class="header-anchor" href="#where-to-configure-it" aria-label="Permalink to &quot;Where To Configure It&quot;">​</a></h2><p>Open:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="IP geolocation" loading="lazy"></p><h2 id="available-settings" tabindex="-1">Available Settings <a class="header-anchor" href="#available-settings" aria-label="Permalink to &quot;Available Settings&quot;">​</a></h2><p>The newer IP geolocation flow supports multiple sources instead of relying on one map service.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>Chooses the display language, such as English, Simplified Chinese, Japanese, French, and others.</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind account ID for MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key.</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key. Useful for Chinese addresses and mainland China IPs.</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key. Supports multilingual IP geolocation.</td></tr></tbody></table><p>Fill in only the services you need. You do not have to configure every field.</p><p>If no key is provided, ImgBed still tries built-in free sources, but stability, language support, and precision may be lower than a service you configure yourself.</p><h2 id="recommended-choices" tabindex="-1">Recommended Choices <a class="header-anchor" href="#recommended-choices" aria-label="Permalink to &quot;Recommended Choices&quot;">​</a></h2><p>If you mainly need Chinese addresses:</p><ol><li>Set IP geolocation language to Simplified Chinese.</li><li>Configure Tencent Map Key.</li><li>Optionally add MaxMind or ipapi as fallback sources.</li></ol><p>If you mainly need English or multilingual addresses:</p><ol><li>Choose the language you need.</li><li>Configure MaxMind Account ID and License Key.</li><li>Add an ipapi Key if you need better multilingual results.</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind needs:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Find the account ID in the MaxMind dashboard and generate a License Key from the License Keys page.</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>After generation, paste the Account ID and License Key into ImgBed and save.</p><p>MaxMind&#39;s free plan is suitable for everyday use, but it has request limits. If the quota is exceeded, ImgBed continues trying other available sources.</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi uses an APILayer API Key.</p><p>Open the ipapi console and copy the API Key shown there.</p><p><img src="'+s+'" alt="ipapi config" loading="lazy"></p><p>Paste it into the <code>ipapi Key</code> field in ImgBed and save.</p><p>ipapi supports multilingual IP geolocation and is useful when you want addresses shown in a selected language. Its free plan also has request limits. If quota runs out, ImgBed continues trying other available sources.</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key is useful for Chinese addresses, especially mainland China IPs.</p><p>When creating a key in Tencent Location Service, enable:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>After creation, paste the key into <code>Tencent Map Key</code> and save.</p><p>If you only need basic Chinese IP geolocation, Tencent Map Key is enough to get started.</p><h2 id="what-to-check-in-user-management" tabindex="-1">What To Check in User Management <a class="header-anchor" href="#what-to-check-in-user-management" aria-label="Permalink to &quot;What To Check in User Management&quot;">​</a></h2><p>User Management is available from the top of the admin panel.</p><p><img src="'+n+'" alt="User management" loading="lazy"></p><p>User Management shows upload activity by IP:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>IP source</td><td>Uploader source IP.</td></tr><tr><td>Address</td><td>Approximate location resolved from the IP.</td></tr><tr><td>Total upload size</td><td>Total file size uploaded by this IP.</td></tr><tr><td>Upload count</td><td>Number of uploads from this IP.</td></tr><tr><td>Upload allowed</td><td>On means uploads are allowed. Off means uploads are blocked.</td></tr></tbody></table><p>Click the arrow on the left to expand the list of files uploaded by that IP.</p><p>The file list shows file name, preview, file size, moderation result, file status, and upload time. When uploads look suspicious, expand the IP first, review the files, then decide whether to block further uploads.</p><p>If an IP is suspicious, turn off <code>Upload allowed</code>. Future uploads from that IP will be blocked.</p><h2 id="search-sort-and-advanced-filters" tabindex="-1">Search, Sort, and Advanced Filters <a class="header-anchor" href="#search-sort-and-advanced-filters" aria-label="Permalink to &quot;Search, Sort, and Advanced Filters&quot;">​</a></h2><p>At the top of User Management, search by IP source or address.</p><p>Sort by time, upload count, or total upload size to find recent uploaders, high-frequency uploaders, or high-usage IPs.</p><p>For deeper investigation, open advanced filters.</p><p><img src="'+o+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters support:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Usage</th></tr></thead><tbody><tr><td>Time range</td><td>Show IPs that uploaded files during a selected period.</td></tr><tr><td>Access status</td><td>Filter by normal, blocked, and similar states.</td></tr><tr><td>Allow/block list</td><td>Filter by allowlist, blocklist, or unset.</td></tr><tr><td>File type</td><td>Show IPs that uploaded images, videos, audio, documents, code, or other files.</td></tr><tr><td>File size</td><td>Filter by uploaded file size range.</td></tr><tr><td>Age rating</td><td>Filter by unset, General, R12+, R16+, R18, and similar ratings.</td></tr><tr><td>File status</td><td>Filter by current file status to investigate abnormal files.</td></tr></tbody></table><p>Click <code>Apply Filters</code> to apply. Use <code>Reset</code> to return to all data.</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>On mobile, User Management switches to card layout.</p><p><img src="'+i+`" alt="Mobile user management" loading="lazy"></p><p>Each card shows IP, address, total upload size, upload count, and the upload allowed switch. You can manage users without horizontal table scrolling.</p><h2 id="if-the-location-looks-wrong" tabindex="-1">If the Location Looks Wrong <a class="header-anchor" href="#if-the-location-looks-wrong" aria-label="Permalink to &quot;If the Location Looks Wrong&quot;">​</a></h2><p>IP geolocation is approximate. It is not a precise street address.</p><p>If the user is behind a proxy, data center, cloud server, or cross-border network, the displayed location may differ from the real location.</p><p>Use this feature to understand rough origin, find abnormal uploads, and assist blocking decisions. Do not treat it as precise tracking.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Address is empty</td><td>The IP may not have resolved yet, or the current source is temporarily unavailable.</td></tr><tr><td>Address language is wrong</td><td>Check IP geolocation language and whether a source supporting that language is configured.</td></tr><tr><td>Address shows a data center</td><td>Many proxies, cloud servers, and crawlers appear as data center or ISP addresses.</td></tr><tr><td>Upload count is high</td><td>Review this IP carefully and block uploads if needed.</td></tr><tr><td>Total upload size is large</td><td>Sort or filter, expand the IP, and inspect specific files.</td></tr><tr><td>Need to restore after blocking</td><td>Turn <code>Upload allowed</code> back on.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Open IP Geolocation in Other Settings</span></span>
<span class="line"><span>-&gt; Choose IP geolocation language</span></span>
<span class="line"><span>-&gt; Fill MaxMind, Tencent Map, or ipapi credentials as needed</span></span>
<span class="line"><span>-&gt; Save settings</span></span>
<span class="line"><span>-&gt; Open User Management</span></span>
<span class="line"><span>-&gt; Review IP source, address, total upload size, and upload count</span></span>
<span class="line"><span>-&gt; Use search, sort, or advanced filters to find abnormal IPs</span></span>
<span class="line"><span>-&gt; Allow or block uploads as needed</span></span></code></pre></div>`,64)])])}const k=d(c,[["render",h]]);export{v as __pageData,k as default};
